func solve(nums []int64) bool {
    n := len(nums)
    for p := 1; p <= n-3; p++ {
        for q := p + 1; q <= n-2; q++ {
            valid := true
            // Check first part 0...p is strictly increasing
            for i := 0; i < p; i++ {
                if nums[i] >= nums[i+1] {
                    valid = false
                    break
                }
            }
            if !valid {
                continue
            }
            // Check second part p...q is strictly decreasing
            for i := p; i < q; i++ {
                if nums[i] <= nums[i+1] {
                    valid = false
                    break
                }
            }
            if !valid {
                continue
            }
            // Check third part q...n-1 is strictly increasing
            for i := q; i < n-1; i++ {
                if nums[i] >= nums[i+1] {
                    valid = false
                    break
                }
            }
            if valid {
                return true
            }
        }
    }
    return false
}
